package br.com.munif.stella.api.dto;

import java.time.Instant;
import java.util.List;

/**
 * DTO representing an audited revision of a person.
 *
 * <p>Used to expose the change history tracked by Hibernate Envers.
 * Each instance of this DTO corresponds to a version of the {@code Pessoa} entity
 * at a specific point in time.</p>
 *
 * @param revisao         sequential revision number generated by Hibernate Envers
 * @param dataHora        date and time when the revision was created (UTC)
 * @param tipo            type of the operation that generated the revision (e.g.: {@code "ADD"}, {@code "MOD"}, {@code "DEL"})
 * @param pessoa          snapshot of the person's data at this revision
 * @param camposAlterados list of field names that were modified in this revision;
 *                        empty on creation (ADD), since all fields are new
 */
public record PessoaRevisaoDTO(
        Number revisao,
        Instant dataHora,
        String tipo,
        PessoaResponseDTO pessoa,
        List<String> camposAlterados
) {
}
